import{_ as a,o as t,c as i,f as n}from"./index.955a41c2.js";const o={},s={class:"padding text-contrast"};function d(r,e){return t(),i("div",s,[...e[0]||(e[0]=[n("<section data-v-08ed1304><h1 data-v-08ed1304>Biography</h1><p data-v-08ed1304><strong data-v-08ed1304>Doctor 6 (Six)</strong> is an Argentine producer and mixer dedicated to the relentless pursuit of sonic precision. His work explores the contrast between the raw aggression of bass music and the melodic atmospheres of Deep House. <br data-v-08ed1304><br data-v-08ed1304> Drawing from a background in IT and mechanics, Six views sound as a complex system to be engineered, focusing on &quot;corrupted&quot; textures and industrial glitches. </p><section data-v-08ed1304><header data-v-08ed1304><h2 data-v-08ed1304>At age 15</h2></header><p data-v-08ed1304> Six began his journey into production using a basic Pentium 4 PC. What started as teenage beatmaking soon turned into an obsession with audio architecture, leading him to explore piano and professional vocal coaching, while also teaching himself guitar. </p></section><section data-v-08ed1304><header data-v-08ed1304><h2 data-v-08ed1304>At age 23</h2></header><p data-v-08ed1304> After completing Sound Technician studies and DJ courses (Vinyl &amp; CDJ), he shifted his focus from beatmaking to the art of mixing. A pivotal mentorship with a Gardel Award-winning engineer marked the beginning of his path as a dedicated mixer. </p></section><section data-v-08ed1304><header data-v-08ed1304><h2 data-v-08ed1304>In recent years</h2></header><p data-v-08ed1304> Six has focused on specialized training in bass music and electronic mixing from Germany. Rather than following trends, he is committed to the craft of sound design, constantly refining his output to bridge the gap between technical grit and melodic clarity. </p></section><section data-v-08ed1304><header data-v-08ed1304><h2 data-v-08ed1304>Today</h2></header><p data-v-08ed1304> His current vision is a collision of worlds: a constant effort to <strong data-v-08ed1304>contrast the raw aggression of Bass Music with deep melodic sensitivity</strong>. By merging experimental sound design with true musicality to avoid generic structures, Six continues to build his own sonic universe\u2014a place where industrial machinery and <strong data-v-08ed1304>spatial atmospheres</strong> converge. </p></section></section>",1)])])}var h=a(o,[["render",d],["__scopeId","data-v-08ed1304"]]);export{h as default};
